INSERT INTO sub_areas (id, attraction_id, name_en, name_zh, body, cover_image_path, sort_order, is_active)
VALUES
  ('chongqing_baixiangju_sa_01', 'chongqing_baixiangju', 'Ground-Floor Riverside Entrance (Starting Point)', '1层临江入口（起点）', 'The riverside entrance on the ground floor of Baixiangju is the starting point of the vertical tour. It features two 2-meter stone elephants, a 1990s residential block hugging the Yangtze and the famous air-raid-shelter-turned-café that has become a viral photo spot for the Chongqing skyline and cable car.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_baixiangju_sa_01.png', 0),
  ('chongqing_baixiangju_sa_02', 'chongqing_baixiangju', '10th-Floor Sky Corridor', '10层空中公共连廊', 'Built in 1996, this 24-floor residential block has no elevator. The 10th-floor corridor links the three towers of the complex, offering unobstructed views of the Yangtze, the cable car, the Raffles City skyline and the Yangtze River Bridge—an iconic filming and viral-photography location famous for Chongqing''s "8D magic."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_baixiangju_sa_02.png', 1),
  ('chongqing_baixiangju_sa_03', 'chongqing_baixiangju', 'Cable-Car Frame Window', '长江索道同框观景窗', 'This framed cable-car shot, captured from the 10th-floor corridor''s east end with a 2–3x telephoto lens, places the Yangtze Cable Car and Baixiangju''s 24-story walk-up in the same frame. The result—an "8D" composition of building, cable car and river—has become a must-shoot for photographers worldwide.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_baixiangju_sa_03.png', 2),
  ('chongqing_baixiangju_sa_04', 'chongqing_baixiangju', '15th-Floor Jiefang East Road Exit (Ending Point)', '15层解放东路出口（终点）', 'This 15th-floor exit connects Baixiangju to Jiefang East Road and the Luohan Temple area via a 30-step descent. The platform offers a striking 3D-traffic view of Jiefang East Road, Minzu Road, Cangbai Road, the cable car and double-decker buses, marking the official end of the Baixiangju vertical tour.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_baixiangju_sa_04.png', 3),
  ('chongqing_zoo_sa_01', 'chongqing_zoo', 'Main Entrance Plaza (Starting Point)', '大门广场（起点）', 'The semi-circular entrance plaza greets visitors with a giant panda flower bed, a golden "Chongqing Zoo" sign, palm and ginkgo trees, and bronze animal statues. It also houses the visitor center, ticket office, souvenir shop and the official park map—making it the natural starting point for any visit.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_zoo_sa_01.jpg', 0),
  ('chongqing_zoo_sa_02', 'chongqing_zoo', 'Panda Hall', '熊猫馆', 'Built in the 1960s and modernized in the 2010s, Panda Hall is a multi-zone complex with indoor halls, outdoor playgrounds, a maternity ward and a kindergarten. Home to 10+ giant pandas, it is one of the largest breeding bases in western China and a flagship for panda research, conservation and education.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_zoo_sa_02.jpg', 1),
  ('chongqing_zoo_sa_03', 'chongqing_zoo', 'Goldfish Hall', '金鱼馆', 'Built in the 1990s and refurbished in 2018, Goldfish Hall is a southwest-China landmark for goldfish appreciation. With four themed zones and ~60 varieties (dragon-eye, fantail, oranda, ranchu, celestial-eye, pearl-scale and more), it is a favorite for family visits and a regular venue for the National Goldfish Competition.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_zoo_sa_03.jpg', 2),
  ('chongqing_zoo_sa_04', 'chongqing_zoo', 'Amphibian and Reptile Hall', '两栖爬行动物馆', 'Opened in 2005, the Amphibian and Reptile Hall is the largest herpetarium in southwest China. With two floors and habitats mimicking rainforest, marsh, rocky desert and river valley, it houses 60+ species and 300+ individuals, plus a "night-creature" interactive zone popular with school groups.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_zoo_sa_04.jpg', 3),
  ('chongqing_zoo_sa_05', 'chongqing_zoo', 'Bird Area', '鸟类区', 'The 15,000 m² Bird Area is the largest and most diverse in the zoo, comprising six themed zones and home to nearly 100 species. Highlights include red-crowned cranes, mandarin ducks, golden pheasants, peafowl, hornbills, macaws, flamingos and the rare Chinese crested tern, with seasonal wild birds joining the resident flocks in spring and autumn.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_zoo_sa_05.jpg', 4),
  ('chongqing_ciqikou_old_town_sa_01', 'chongqing_ciqikou_old_town', 'Huangjueping Memorial Arch', '黄桷坪牌坊', 'Rebuilt in 2010 in classic Ming style, this 12-meter stone archway is the official entrance to Ciqikou Ancient Town. Flanked by two 100-year-old banyan trees and the "Ciqikou" name tablet, it marks the starting point of both the main street and the riverside tour routes.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_ciqikou_old_town_sa_01.jpg', 0),
  ('chongqing_ciqikou_old_town_sa_02', 'chongqing_ciqikou_old_town', 'Zhong Family Mansion', '钟家院', 'Built in the Xianfeng era (1851–1861), the 1,500 m² Zhong Mansion is a three-bay Qing residence with a front shop and a back living area. Converted into the Bayu Folk-House Museum in 1998, it displays wedding customs, carved beds, ancestral tablets and other late-imperial artifacts of Bayu culture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_ciqikou_old_town_sa_02.jpg', 1),
  ('chongqing_ciqikou_old_town_sa_03', 'chongqing_ciqikou_old_town', 'Baoshan Palace', '宝善宫', 'Built in 1886 as a Jiangxi merchant guild hall, Baoshan Palace is the best-preserved of Ciqikou''s "Nine Palaces and Eighteen Temples." Refurbished in 2010, its teahouse hosts Sichuan opera seating performances daily, with bamboo chairs and 5-CNY covered-bowl tea—a perfect taste of old Chongqing.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_ciqikou_old_town_sa_03.jpg', 2),
  ('chongqing_ciqikou_old_town_sa_04', 'chongqing_ciqikou_old_town', 'Xin''s Grocery', '鑫记杂货铺', 'Founded in 1894, Xin''s is a fourth-generation grocery and the only shop still using the traditional "front-shop-back-workshop" layout on Ciqikou''s main street. It sells malt sugar, sesame candy, hand-made soy sauce, Sichuan pepper broad-bean paste and dozens of other old Chongqing snacks—a living window into late-imperial market culture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_ciqikou_old_town_sa_04.jpg', 3),
  ('chongqing_ciqikou_old_town_sa_05', 'chongqing_ciqikou_old_town', 'Jusenmao Sauce Garden Site', '聚森茂酱园旧址', 'Founded in 1911, Jusenmao was once the largest sauce maker in Ciqikou, producing 500,000 jin of soy sauce, vinegar, bean paste and pickles a year. Partially demolished in 2003, its front shop and sun-curing yard were rebuilt in 2010 as a museum of traditional sauce culture, with 60+ vats on display.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_ciqikou_old_town_sa_05.jpg', 4),
  ('chongqing_ciqikou_old_town_sa_06', 'chongqing_ciqikou_old_town', 'Ciheng Street', '磁横街', 'Built along the Jialing River cliff, the 200-meter "half-side street" is Ciqikou''s most authentic riverside market. With stilted houses, stone steps, dock-worker statues and ancient banyans, it preserves the late-Qing water-and-land transport hub that made Ciqikou a leading commercial port in eastern Sichuan.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_ciqikou_old_town_sa_06.jpg', 5),
  ('chongqing_ciqikou_old_town_sa_07', 'chongqing_ciqikou_old_town', 'Baolun Temple', '宝轮寺', 'Founded in 1008 during the Tang dynasty, Baolun Temple is the origin of the "White Rock" name for Ciqikou. Rebuilt in the Kangxi era and bestowed the imperial name "Baolun Chan Temple" by Emperor Qianlong, it preserves a Kangxi plaque, Song stone Buddhas and Ming gilt-bronze statues—the three treasures of the temple.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_ciqikou_old_town_sa_07.jpg', 6),
  ('chongqing_ciqikou_old_town_sa_08', 'chongqing_ciqikou_old_town', 'Yinglongmen Wharf', '迎龙门码头', 'Dating back to the Ming dynasty, Yinglongmen Wharf was one of the four major Jialing River ports in the late-Qing era, handling 300,000 tons of cargo annually. Restored in 2010 with its stone steps, mooring stones and river pavilion, it now hosts folk performers and is the boarding point for Jialing River cruise boats.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_ciqikou_old_town_sa_08.jpg', 7),
  ('chongqing_ciqikou_old_town_sa_09', 'chongqing_ciqikou_old_town', 'Nine-Stone-Cap Riverside', '九石缸河滩', 'The viral "Little Kenting" beach, named after nine Qing-era stone vats once used to store drinking water for porcelain-export boats. Six of the nine vats survive today, lining a sandy Jialing River bank popular from May to October for wading, sunset views and winter misty mornings.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_ciqikou_old_town_sa_09.jpg', 8),
  ('chongqing_ciqikou_old_town_sa_10', 'chongqing_ciqikou_old_town', '"Ciqi Changge" Immersive Experience Hall', '磁器长歌体验馆', 'Opened in May 2023, Ciqi Changge is Ciqikou''s first large-scale immersive night-experience hall. Across five acts—Ancient Wharf, Old Street, Porcelain Kiln, Guild Hall, Wartime Capital—it uses AR, holograms, live performance and interactive lighting to compress 1,000 years of local history into a 60-minute walking show.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_ciqikou_old_town_sa_10.jpg', 9),
